def hallerEActive() {
		my active = false;
		if (call isUSM()) {
			active = true;
		} else {
			 my country = partnertable['country'];
			 active = Size(TableRows(haller_e_country, 'iso', country, true)) gt 0;

		};

		return active;
	};

def verbraucherSnapPos(laenge) {
      my positions = List();
      my links = List();
      my mitte = List();
      my rechts = List();
      my x = 0;
      my z = 0;
      laenge = laenge / 10;
      links = List(Vector(x,- laenge/2 + 10,z),Vector(x,- laenge/2 + 25,z));
      mitte = List(Vector(x,-7.5,z),Vector(x,7.5,z));
      rechts = List(Vector(x,laenge/2 - 25,z),Vector(x,laenge/2 - 10,z));
      /* if (laenge eq 15 ) {  
        mitte = List(Vector(-7.5,0,z),Vector(7.5,0,z));  
        positions = ListAdd(positions,mitte);
      }  */
      if (laenge eq 15 or laenge eq 35 or laenge eq 75) {      
        positions = ListAdd(positions,mitte);
      }  
      if (laenge eq 50 or laenge eq 75) {      
        positions = ListAdd(positions,links);
        positions = ListAdd(positions,rechts);
      }  

      return positions;
   }

def volumeHallerE(part) {
     my hallerE = false;  
     hallerE = Bool(Size(FilterList(GetVolumeRefParts(part),'element',`not Feature(element,'f_hallerE');`)));
     return hallerE;
   }

def rohrToBlechConnected(part,blech) {
  my connected = false;
  my dock = null;
  my connection = null;
  for (my index : IndexList(4)) {
    index = index + 1;
    dock = Dock(part,'rohr2blech',index);
    connection = DockGetConnectedPart(dock);
    if (connection eq blech) {
      connected = true;
      break;
    }
  }
  return connected;
  }

def rohrToGlasConnected(part,glas) {
	  my connected = false;
	  my dock = null;
	  my glasdock = null;
	  my connection = null;
	  for (my index : List(1,2,3,4,11,12,13,14)) {
	    dock = Dock(part,'rohr2glashalter',index);
	    connection = DockGetConnectedPart(dock);
	    if (connection) {
	      glasdock = Dock(connection,'glashalter2glas',1);
	      connection = DockGetConnectedPart(glasdock);
	      if (connection eq glas) {
	        connected = true;
	        break;
	      }
	    }
	  }
	  return connected;
	  }

def rohrRichtungDefault(part) {
     my richtung = 'richtung-innen-25';  
     if (call verbraucherHorizontalVerkleidung(part,'glas')) {
     	my volumes = GetRefVolumes(part, 'mainstructure');
     	my volume = FilterList(volumes, 'v', `not (RelativePartPos(v,part)['z'] gt 0);`)[0];
     	if (volume) {
     		my has_tuer = ChildOfTypeDeep(volume, 'at_tuerset');
     		richtung = not has_tuer ? 'richtung-innen-45' : richtung;
     	}
     }
     if (call rohrRichtungAussen(part,'default')) {
       richtung = 'richtung-aussen-270';   
     }
      if (call rohrRichtungOben(part,'default')) {
       richtung = 'richtung-oben-180';   
     }

     return richtung;
   }

def rohrRichtungInnen(part) {
    my innen = true;
    my bodenrohr = PartPos(part)['z'] lt 10;
    my laenge750 = PartAttr(part,'hc_length') eq '750';
    my blech_unten = call verbraucherVertikalVerkleidung(part,'blech','unten');
    my glas_unten = call verbraucherVertikalVerkleidung(part,'glas','unten');
    my blech_seite = call verbraucherHorizontalVerkleidung(part,'blech');
    my glas_seite = call verbraucherHorizontalVerkleidung(part,'glas');
    my blechwinkel = blech_unten and blech_seite;
    my glaswinkel = glas_unten and glas_seite;
    my mixwinkel = (glas_unten and blech_seite and not laenge750) or blech_unten and glas_seite;
    my registratur = call verbraucherTuere(part,'registraturset','oben','seite'); 

    if ( (blechwinkel or mixwinkel or registratur) and not bodenrohr) {
      innen = false;
    }

    if (glas_unten and blech_seite and not laenge750){
   		if (call rohrRichtungAussen(part,'valid')){
   			innen = true;
   		}
    }

    return innen;
  }

def rohrRichtungOben(part,mode) {
    my oben = false;
    my nichtverkleidet = false;
    my ohnetuere = false;
    my laenge750 = PartAttr(part,'hc_length') eq '750';
    my bodenrohr = PartPos(part)['z'] lt 10;
    my blechwinkel = false;

    nichtverkleidet = not call verbraucherVertikalVerkleidung(part,'neutral','oben');
    ohnetuere = not call verbraucherTuere(part,'neutral','oben','vorne') or (call tuereSeiteRohr(part) and nichtverkleidet);

    if (not laenge750 or call verbraucherHorizontalVerkleidung(part,'glas') or call verbraucherHorizontalVerkleidung(part,'einsatz')) {
      /* Fuer Glas horizontal oder Rohre kleiner als 750 */
      oben = nichtverkleidet and ohnetuere;
    } else {
      blechwinkel = call verbraucherHorizontalVerkleidung(part,'blech') and call verbraucherVertikalVerkleidung(part,'blech','unten');
      oben = nichtverkleidet and ohnetuere and blechwinkel and not bodenrohr;
    }

    if (mode eq 'default') {
       oben  = oben and call posVolume(part,'unten') and call posVolume(part,'seiteunten') and not call posVolume(part,'oben') and not bodenrohr;
    } else {
      oben = oben;
    }
    return oben;
  }

def rohrRichtungAussen(part,mode) {
    my aussen = true;
    my laenge750 = PartAttr(part,'hc_length') eq '750';
    my bodenrohr = PartPos(part)['z'] lt 10;
    my verkleidung = true;
    my kuha = false;
    my glas = false;
    my blech = false;
    my blechuntenoben = false;
    my winkel = false;
    my winkelT = false;
    my blechwinkel = false;
    my glasblechwinkel = false;
    my blechobenglasunten750 = false;
    my tuere = true;
    my neutral_oben = false;
    my glasoben = false;
    /* call posVolume(part,'seiteoben') kontrolliert, dass es nicht seitlich ein Volumen hat */
    tuere = not call verbraucherTuere(part,'neutral','unten','vorne');
    winkel = call verbraucherHorizontalVerkleidung(part,'neutral') and call verbraucherVertikalVerkleidung(part,'neutral','unten') and not bodenrohr;
    winkel = winkel and not call posVolume(part,'seiteunten');  
    winkelT = winkel and call verbraucherVertikalVerkleidung(part,'neutral','oben') and not call posVolume(part,'seiteoben');
    glas = call verbraucherHorizontalVerkleidung(part,'glas');
    blech =  call verbraucherVertikalVerkleidung(part,'blech','unten');
    blechobenglasunten750 = call verbraucherHorizontalVerkleidung(part,'blech') and call verbraucherVertikalVerkleidung(part,'glas','unten') and laenge750;
    blechwinkel = blech and call verbraucherVertikalVerkleidung(part,'blech','unten') and not call posVolume(part,'seiteunten') and not bodenrohr;
    glasblechwinkel = glas and blech and not call posVolume(part,'seiteunten') and not bodenrohr;
    glasoben =  call verbraucherVertikalVerkleidung(part,'glas','oben');

    if (laenge750 and mode eq 'valid'){
      kuha = call verbraucherHorizontalVerkleidung(part,'einsatz_blech');
    }
    if (mode eq 'default') {
      aussen = ((winkel and tuere) or glasblechwinkel or blechwinkel or winkelT) and not blechobenglasunten750;
    } else if (mode eq 'valid') {
      verkleidung = ((not laenge750 and not call posVolume(part,'seiteunten')) or (laenge750 and kuha) or 
                    (laenge750 and glas) or glasoben or (laenge750 and blechwinkel)) and not blechobenglasunten750;
      tuere = not laenge750 or (laenge750 and tuere);

      aussen = verkleidung and tuere;

    }


    return aussen;
  }

def rohrRichtungValid(part) {
     /* innen-oben-aussen */
     my valid = '---';
     my valides = List();
     my innen = call rohrRichtungInnen(part);
     my oben = call rohrRichtungOben(part,'valid');
     my aussen = call rohrRichtungAussen(part,'valid');
     if (innen) {
       valides = ListAdd(valides,'innen');
     }
     if (oben) {
       valides = ListAdd(valides,'oben');
     }
     if (aussen) {
       valides = ListAdd(valides,'aussen');
     }
     valid = ListToString(valides,'-');
     return valid;
   }

def dockRotationKugel(part,richtung) {
    my rotation = 0;
    /* Richtung des Z-Richtung */
    my vector_z = LocalPos(part, VectorAdd(Vector(0,0,-1), PartPos(part)));
    my x = Round(vector_z['x']);
    my y = Round(vector_z['y']);
    my z = Round(vector_z['z']);
    my kugelrotz = PartRot(part)['z'];
    my rotx = 0;
    my roty = 0;
    my rotz = 0;

    if (richtung eq 'x') {
      if (z eq 1) {
        rotx = -180;
      } else if (y eq -1) {
        rotx = -90;
      }  else if (y eq 1) {
        rotx = 90;
        if (kugelrotz eq -180) {
          rotx = 90;
        }
      }
      rotation = rotx;
    }
    if (richtung eq 'y') {
      if (x eq 1) {
        roty = -90;
      } else if (y eq 1 and kugelrotz eq -180) {
        roty = 0;
      }
      rotation = roty;
    }
    if (richtung eq 'z') {
      if (y eq 1 and kugelrotz eq -180) {
        rotz = 180;
      }
      rotation = rotz;
    }
    return rotation;
   }

def rotationsWinkel(part) {
    my angle = 0;
    my eparts = GetComponentListOfConnectionId(ConnectionId(part));
    my rohre = FilterList(eparts,'element',`not IsSubTypeOf(element,'normalrohr');`);
    rohre = FilterList(rohre,'element',`not call horizontalPart(element);`);
    my richtung = Feature(part,'f_rohrRichtung');
    richtung = StringToList(richtung,'-')[2];
    my visavis = call visaviRohr(part,rohre);
    my down = LocalPos(part, VectorAdd(Vector(0,0,-1), PartPos(part)));
    my innen = VectorNormalize(LocalPos(part, PartPos(visavis)));

    my downAngle = Deg(VectorAngle(Vector(1, 0, 0), down, Vector(0,1,0)));
    if (downAngle lt 0) {
      downAngle = downAngle + 360;
    }

    my innenAngle = Deg(VectorAngle(Vector(1, 0, 0), innen, Vector(0,1,0)));
    if (innenAngle lt 0) {
      innenAngle = innenAngle + 360;
    }

    if (innenAngle gt downAngle) {
      angle = downAngle + richtung;
    } else {
      angle = downAngle - richtung;
    }
    return angle;
  }

def directionOfLight(part) {
   my winkel = call rotationsWinkel(part);
   my x = Cos(Rad(winkel));
   my z = Sin(Rad(winkel));
   my vector = Vector(x, 0.0, -z);
   return vector;
   }

def verbraucherHorizontalVerkleidung(part,typ) {
    my eingebaut = false;
    my tuere = null;
    my volumes = GetRefVolumes(part, 'mainstructure');
    my unten = volumes[0];
    my verkleidung = List();
    my einsatz = List();
    my blech = List();
    my glas = List();
    if (typ eq 'blech' or typ eq 'neutral') {
      verkleidung = FilterList(GetVolumeRefParts(unten),'element',`not IsSubTypeOf(element,'ct_standardblech');`);
      verkleidung = FilterList(verkleidung,'element',`Round(PartPos(element)['z']) ne Round(PartPos(part)['z']);`);
      blech = verkleidung;
    } else if (typ eq 'glas' or typ eq 'neutral') {
      verkleidung = FilterList(GetVolumeRefParts(unten),'element',`not IsSubTypeOf(element,'glasverkleidung');`);
      verkleidung = FilterList(verkleidung,'element',`Round(PartPos(element)['z']) ne Round(PartPos(part)['z']);`);
      glas = verkleidung;
    } 
    if (typ eq 'neutral') {
      verkleidung = blech or glas;
    }
    if (not Bool(verkleidung) or BeginsWith(typ,'einsatz')) {          
        verkleidung = FilterList(GetVolumeRefParts(unten),'element',`not IsSubTypeOf(element,'einsatzverkleidung');`);
        verkleidung = FilterList(verkleidung,'element',`Round(PartPos(element)['z']) ne Round(PartPos(part)['z']);`);
        einsatz = verkleidung;

        if (EndsWith(typ,'blech') or typ eq 'neutral') {
          verkleidung = FilterList(verkleidung,'element',`Feature(element,'Metallfarbe') ne '02';`); 
          blech = verkleidung;

        } else  if (EndsWith(typ,'glas') or typ eq 'neutral') {
          verkleidung = FilterList(verkleidung,'element',`Feature(element,'Metallfarbe') eq '02';`);
          glas = verkleidung;
        } 
        if (typ eq 'neutral') {
         verkleidung = blech or glas;
        }
    }     
    eingebaut = Bool(Size(verkleidung));

    return eingebaut;
  }

def verbraucherVertikalVerkleidung(part,typ,pos) {
    my eingebaut = false;
    my hasblech = false;
    my hasglas = false;
    my vol = call posVolume(part,pos);
    my verkleidung = List();

    if (typ eq 'blech' or typ eq 'neutral') {
      verkleidung = FilterList(GetVolumeRefParts(vol),'element',`not IsSubTypeOf(element,'metallverkleidung');`);
      verkleidung = FilterList(verkleidung,'element',`Round(PartPos(element)['z']) eq Round(PartPos(part)['z']);`);
      verkleidung = FilterList(verkleidung,'element',`not call rohrToBlechConnected(part,element);`);  
      hasblech = Bool(Size(verkleidung));
    } 
    if (typ eq 'glas' or typ eq 'neutral') {
      verkleidung = FilterList(GetVolumeRefParts(vol),'element',`not IsSubTypeOf(element,'glasverkleidung');`);
      verkleidung = FilterList(verkleidung,'element',`Round(PartPos(element)['z']) eq Round(PartPos(part)['z']);`);
      verkleidung = FilterList(verkleidung,'element',`not call rohrToGlasConnected(part,element);`);
      hasglas = Bool(Size(verkleidung));
    } 
    if (typ eq 'neutral') {
      eingebaut = hasblech or hasglas;
    } else {
      eingebaut = Bool(Size(verkleidung));
    }

    return eingebaut;
    }

def tuereSeiteRohr(part) {
      my seitenrohr = false;
      my scherengelenke = List();
      my teleskopauszuege = List();
      my distx = 0;
      my volumes = List();
      my seitenteile = List();
      my vol_unten  = call posVolume(part,'unten');
      my vol_seiteunten  = call posVolume(part,'seiteunten');

      if (vol_unten) {
         volumes = ListAdd(volumes,vol_unten);
      }
      if (vol_seiteunten) {
         volumes = ListAdd(volumes,vol_seiteunten);
      }

      for (my vol : volumes) {
         scherengelenke = ChildrenListOfTypeDeep(vol,'scherengelenk');
         if (Size(scherengelenke)) {
            seitenteile = JoinList(seitenteile,scherengelenke);
         }
         teleskopauszuege = ChildrenListOfTypeDeep(vol,'teleskopauszug');
         if (Size(teleskopauszuege)) {
            seitenteile = JoinList(seitenteile,teleskopauszuege);
         }
      } 
      if (Size(seitenteile)) {
        for (my seitenteil : seitenteile) {
          distx = Abs(RelativePartPos(seitenteil,part)['x']);
          if (distx lt 3) {
            seitenrohr = true;
            break;
          }
        }
      }

      return seitenrohr;
  }

def verbraucherTuere(part,tuertyp,pos,tiefe) {
      my eingebaut = false;
      my ausziehtuere = false;
      my klapptuere = false;
      my einschubtuere = false;
      my schubladenset = false;
      my schublade = null;
      my registraturset = false;
      my rost = null;
      my tuere = null;
      my teleskop = null;
      my dock = null;
      my dof = 0;
      my dist = 0;
      my disty = 0;
      my verkleidung = List();
      my partposz = Round(PartPos(part)['z']);

      my volposz = 0;
      my vol = call posVolume(part,pos);
      my volposz = Round(PartPos(vol)['z']);
      if (tuertyp eq 'auszieh' or tuertyp eq 'neutral') {
        if (vol) {
          tuere = ChildOfTypeDeep(vol,'ausziehtuertablarset');
        } 
        if (tuere) {
           /* checks vorne oder hinten */
           teleskop = ChildOfTypeDeep(tuere,'teleskopauszug');
             dock = DocksOfType(teleskop, 'ct_teleskop2tablar')[0];
             dof = GetDOFValue(dock);
             dist = Abs(RelativePartPos(ChildOfTypeDeep(tuere,'tablarwinkel'),part)['y'] + dof);
           if (tiefe eq 'vorne') {
              ausziehtuere = dist lt 1;
           } else if (tiefe eq 'hinten') {
              ausziehtuere = dist gt 1;
           }
        }
      }
      if (tuertyp eq 'klapp' or tuertyp eq 'neutral') {
        if (vol) {
          tuere = ChildOfTypeDeep(vol,'klapptuerset');
        }
        if (tuere) {
           /* checks vorne oder hinten */
           dist = Abs(RelativePartPos(ChildOfTypeDeep(tuere,'scherengelenk'),part)['y']);
           if (tiefe eq 'vorne') {
              klapptuere = dist lt 11;
           } else if (tiefe eq 'hinten') {
              klapptuere = dist gt 11;
           }
        }
      }
      if (tuertyp eq 'einschub' or tuertyp eq 'neutral') {
        if (vol) {
          tuere = ChildOfTypeDeep(vol,'einschubtuerset');
        } 
        if (tuere) {
          /* checks vorne oder hinten */
          dist = RelativePartPos(ChildOfTypeDeep(tuere,'einschubtuergelenk'),part)['y'];
          if (tiefe eq 'vorne') {
             einschubtuere = dist gt 0;
          } else if (tiefe eq 'hinten') {
             einschubtuere = dist lt 0;
          }
        }

      }
      if (tuertyp eq 'schublade' or tuertyp eq 'neutral') {
        if (vol) {
          tuere = ChildOfTypeDeep(vol,'schubladenauszugset');
        } 
        if (tuere) {
          schublade = ChildOfType(tuere,'schubladenauszug');
          dist = RelativePartPos(schublade, part);
          disty = Round(dist['y']);
          if (pos eq 'unten' and tiefe eq 'vorne' and partposz gt 4 and disty eq 25) {
            schubladenset = true;
          }
        }
      }

      if (tuertyp eq 'registraturset' or tuertyp eq 'neutral') {
        if (vol) {
          tuere = ChildOfTypeDeep(vol,'registraturset');
        } 
        if (tuere) {
          rost = ChildOfType(tuere,'rost');
          dist = RelativePartPos(rost, part);
          disty = Abs(Round(dist['y']));
          if (pos eq 'oben' and tiefe eq 'vornehinten' and disty eq 25) {
            registraturset = true;
          }
          if (pos eq 'oben' and tiefe eq 'seite' and disty ne 25) {
            registraturset = true;
          }
        }
      }

      eingebaut = ausziehtuere or klapptuere or einschubtuere or schubladenset or registraturset;

      /* Check on Reflektorfolie notwendig ist */
      if ((ausziehtuere or klapptuere) and EndsWith(pos,'folie')) {
         eingebaut = partposz gt volposz;
      }


      return eingebaut;
  }

def isPickable(part) {
      my pick = true;      
      if (Feature(part,'f_hallerEditE'))  {
        pick = false;
      }  
      return pick;
   }

def showVerbraucherPos(part,pos,variante) {
      my show = false;
      my verbraucher = 'f_verbraucher';
      my vpos = 'f_verbraucher' ++ pos; 
      my korrektur = PartAttr(part,'hc_length') eq 750;
      if (Feature(part,'f_hallerEditE') or EnvValue('PDF.Print.HallerE')) {
        if (Feature(part,'f_hallerE') and EndsWith(Feature(part,'f_rohrtyp'),'verbraucher')) {
          if (variante eq 'basis')  {
            show = true;
          } else if (variante eq 'sensor') {
             if (EndsWith(Feature(part,vpos),'usb-charger') or EndsWith(Feature(part,vpos),'sensor'))  {
                show = true;
             }
          } else if (variante eq 'direction') {
                 show = true;
          } else if (variante eq 'laenge') {
              show = 2;
              if ( EndsWith(Feature(part,vpos),'usb-charger') ) {
                 show = 8;
             }
          } else if (variante eq 'trans') {
              if (pos eq 'M') {
                 show = -7;
                 if (korrektur) {
                    show = 7;
                  }
                 if ( EndsWith(Feature(part,vpos),'usb-charger') ) {
                   show = -4;
                 }
              } else if (pos eq 'L') {
                  show = -17;
                  if (korrektur) {
                    show = -15;
                  }
                  if ( EndsWith(Feature(part,vpos),'usb-charger') ) {
                    show = -13;
                    if (korrektur) {
                      show = -26;
                    }
                  }
               } else if (pos eq 'R') {
                  show = 2;
                  if (korrektur) {
                    show = 30;
                  }
                  if ( EndsWith(Feature(part,vpos),'usb-charger') ) {
                    show = 5;
                    if (korrektur) {
                      show = 18;
                    }
                  }
               }   
            }
         }
      }        
      return show;
   }

def kugel2trafoActive(part,index) {
      my active = false;
      my hallerE = Bool(Feature(part,'f_kugelEinspeisung'));
      my dock = Dock(part,'kugel2rohr', index);
      active =  not DockGetConnectedPart(dock) and hallerE;
      return active;
   }

def displayHallerE(part) {
    my show = (Bool(Feature(part,'f_hallerEditE')) and Bool(EnvValue('CO.displayHallerE'))) or Bool(EnvValue('PDF.Print.HallerE'));
    return show;
  }

def transparentHallerE(part) {
      my active = false;
      my transparent = IsSubTypeOf(part,'verkleidung') or IsSubTypeOf(part,'zwischenwand') or IsSubTypeOf(part,'ct_tablar') or 
                       IsSubTypeOf(part,'ct_EinsaetzeAusruestung') or IsSubTypeOf(part,'metalltuer') or 
                       IsSubTypeOf(part,'beschlag') or IsSubTypeOf(part,'stdklemmhalter') or IsSubTypeOf(part,'ct_inosBoxKonzept') or 
                       IsSubTypeOf(part,'ct_pflanzenAddition') or GetTypeName(part) eq 'co_schutzring'; 
      active = call displayHallerE(part) and transparent and 
               not IsSubTypeOf(part,'co_trafo_E') and not IsSubTypeOf(part,'rohrgriff') and 
               GetTypeName(part) ne 'gCE_ContextZone' and not BeginsWith(GetTypeName(part), 'kugel_stift') ;
      return active;
   }

def stromkreisMaterial(part) {
      my material = '-101';
      if (IsSubTypeOf('co_trafo_E')) {
        material = '-102';
      }
      my stromkreis = Feature(part,'f_stromkreis');
      if (call displayHallerE(part))  {
        material = stromkreis;
      }         
      return material;
   }

def rohrMaterial(part) {
      my material = '-101';
      my leitend = not EndsWith(Feature(part,'f_rohrtyp'),'normal');
      if (leitend) {
        material = call stromkreisMaterial(part);
      }         
      return material;
   }

def verbraucherMaterial(part,pos,variante) {
      my material = 'rohrE1';
      my vpos = 'f_verbraucher' ++ pos;
      my verbraucher = Feature(part,vpos);
      if (variante eq 'basis') {
        if (BeginsWith(verbraucher,'dummy') or BeginsWith(verbraucher,'usb-charger')) {
           material = '30';
        } else if (StringContains(verbraucher,'warmweiss')) {
           material = '32';
        } else if (StringContains(verbraucher,'kaltweiss')) {
           material = '24';
        }
      } else if (variante eq 'sensor') {
          material = '30';
          if (BeginsWith(verbraucher,'usb-charger')) {
            material = '24';
          }
      }
      return material;
    }

def noSnapHallerE(targetdock,moveddock) {
     my active = false;
     my active1 = false;
     my moved = DockGetPart(moveddock);
     my target = DockGetPart(targetdock);
     my vertical = not call horizontalPart(target);
     my verbraucher = EndsWith(Feature(DockGetPart(moveddock),'f_rohrtyp'),'verbraucher');
     my movable = call shelfIsMovable(target);

     my nosnap = (vertical and verbraucher) or (movable and verbraucher);
     my einschub = call verbraucherTuere(target,'einschub','unten','vorne');
     my schublade = call verbraucherTuere(target,'schublade','unten','vorne');
     my registraturset = call verbraucherTuere(target,'registraturset','oben','vornehinten');
     /* schublade = false;  */
     my schub = einschub or schublade;
     my auszieh = call verbraucherTuere(target,'auszieh','unten','vorne');
     my klapp = call verbraucherTuere(target,'klapp','unten','vorne');
     my richtungwrong = Feature(target,'f_rohrRichtung') le 45;
     my auszieh2 = call verbraucherTuere(target,'auszieh','oben','vorne');
     my klapp2 = call verbraucherTuere(target,'klapp','oben','vorne');
     my richtungwrong2 = Feature(target,'f_rohrRichtung') ne 270;
     my usb = Feature(moved,'f_verbraucher') eq 'usb-charger';
     my led = not EndsWith(Feature(moved,'f_verbraucher'),'er') and  Feature(target,'f_rohrRichtung') eq 'richtung-oben-180';
     /* wenn Richtung 180 gesetzt, dann geht der USB bei einer Klapptuere */
     my klappunten = (auszieh or klapp) and richtungwrong and not call tuereSeiteRohr(target) and usb and Feature(target,'f_rohrRichtung') ne 'richtung-oben-180';
     my klappoben = (auszieh2 or klapp2) and richtungwrong2 and not call tuereSeiteRohr(target) and usb;
     my kugelstift = call snapHallerEtoKugelStiftManuell(target);
     /* keine Verinderung my sensor = EndsWith(Feature(moved,'f_verbraucher'),'sensor' );
     my nosensor = sensor and not call validSensorHallerE(target); 
     WriteInfoLog('no ' ++ nosnap ++ ',schub ' ++ schub ++ ',ku ' ++ klappunten ++ ',ko ' ++ klappoben ++ ',reg ' ++ registraturset ++ ',led ' ++ led ++ ',ks ' ++ kugelstift);
     */
     active = nosnap or schub or klappunten or klappoben or registraturset or led or kugelstift;
     return active;
   }

def validUSBhallerE(part) {
     my active = false;

     my einschub = call verbraucherTuere(part,'einschub','unten','vorne');
     my schublade = call verbraucherTuere(part,'schublade','unten','vorne');
     my schub = einschub or schublade;
     my auszieh = call verbraucherTuere(part,'auszieh','unten','vorne');
     my klapp = call verbraucherTuere(part,'klapp','unten','vorne');
     my klapp_unten = klapp and (Feature(part,'f_rohrRichtung') ne 'richtung-oben-180' or PartAttr(part, 'hc_length') eq '750');
     my auszieh2 = call verbraucherTuere(part,'auszieh','oben','vorne');
     my tuere = auszieh or klapp_unten or auszieh2;

     active = not tuere or call tuereSeiteRohr(part);
     return active;
   }

def validSensorHallerE() {
    my conflicts = List(); 
    my tuere = true;
    my rohre = GetComponentListOfType('normalrohr');
    my verbraucherrohre = FilterList(rohre,'element',`Feature(element,'f_rohrtyp') ne 'rohr-verbraucher';`);
    my sensorrohre = FilterList(verbraucherrohre,'element',`not call verbraucherEinsatzTypen(element,'sensor');`);
    for (my rohr : sensorrohre) {
      tuere = call verbraucherTuere(rohr,'klapp','unten','vorne') or call verbraucherTuere(rohr,'auszieh','unten','vorne');
      if ( Feature(rohr,'f_rohrRichtung') ne 'richtung-innen-25' or not tuere) {
        conflicts = ListAdd(conflicts, rohr);
      }
    }
    return conflicts;
    }

def lichtVerbraucherFarbeE(part,pos) {
      my farbe = 'none';
      my verbraucher = 'f_verbraucher';
      my vpos = 'f_verbraucher' ++ pos; 
      if ( EndsWith(Feature(part,'f_rohrtyp'),'verbraucher')) {
        farbe = Feature(part,vpos);
        if (StringContains(farbe,'kaltweiss')) {
          farbe = 'kaltweiss';
        } else if (StringContains(farbe,'warmweiss')) {
          farbe = 'warmweiss';
        } else {
          farbe = 'none';
        }
      }
      return farbe;
   }

def lichtFarbeE(part) {
      my farbe = 'none';
      my none = 0;
      my kaltweiss = 0;
      my warmweiss = 0;
      my verbraucherL = '';
      my verbraucherM = '';
      my verbraucherR = '';
      if ( EndsWith(Feature(part,'f_rohrtyp'),'verbraucher')) {
        verbraucherL = Feature(part,'f_verbraucherL');
        verbraucherM = Feature(part,'f_verbraucherM');
        verbraucherR = Feature(part,'f_verbraucherR');
        if (StringContains(verbraucherL,'kaltweiss')) {
          kaltweiss = kaltweiss + 1;
        } else if (StringContains(verbraucherL,'warmweiss')) {
          warmweiss = warmweiss + 1;
        } else {
          none = none + 1;
        }
        if (StringContains(verbraucherM,'kaltweiss')) {
          kaltweiss = kaltweiss + 1;
        } else if (StringContains(verbraucherM,'warmweiss')) {
          warmweiss = warmweiss + 1;
        } else {
          none = none + 1;
        }       
        if (StringContains(verbraucherR,'kaltweiss')) {
          kaltweiss = kaltweiss + 1;
        } else if (StringContains(verbraucherR,'warmweiss')) {
          warmweiss = warmweiss + 1;
        } else {
          none = none + 1;
        }       
        if (none lt 3) {
          if(warmweiss gt kaltweiss){
           farbe = 'warmweiss';
          }else{
           farbe = 'kaltweiss';
          }
        }
      }
      return farbe;
   }

def shelfIsMovable(part) {    
    my active = false;
    my insides = GetComponentListOfConnectionId(ConnectionId(part));
    my bodenelemente = FilterList(insides,'element',`not IsSubTypeOf(element,'bodenelement');`);
    my rollen = FilterList(bodenelemente,'element',`PartAttr(element,'usedHallerE');`);
    if (Size(rollen)) {
       active = true;
    }
    return active;
  }

def verbraucherLeistung(part) {
    my leistung = 0;
    my properties = List('pr_verbraucherL','pr_verbraucherM','pr_verbraucherR');
    for (my property : properties) {
      if (PropertyActive(part, property)) {
        if (BeginsWith(Property(part,property),'led')) {
           leistung = leistung + 1.5;
        } else if (BeginsWith(Property(part,property),'usb')) {
           leistung = leistung + 6.5;
        }
      }
    }
    return leistung;
    }

def verbraucherEinsatzTypen(part,einsatz) {
    my verbaut = false;
    my properties = List('pr_verbraucherL','pr_verbraucherM','pr_verbraucherR');
    for (my property : properties) {
      if (PropertyActive(part, property)) {
        if (StringContains(Property(part,property),einsatz)) {
           verbaut = true;
        }
      }
    }
    return verbaut;
    }

def fehlenderSensorTuere() {
    my conflicts = List(); 
    my rohre = GetComponentListOfType('normalrohr');
    my verbraucherrohre = FilterList(rohre,'element',`Feature(element,'f_rohrtyp') ne 'rohr-verbraucher';`);
    verbraucherrohre = FilterList(verbraucherrohre,'element',`Feature(element,'f_rohrRichtung') ne 'richtung-innen-25 ';`);
    my klapprohre =  FilterList(verbraucherrohre,'element',`not call verbraucherTuere(element,'klapp','unten','vorne');`);
    my ausziehrohre =  FilterList(verbraucherrohre,'element',`not call verbraucherTuere(element,'auszieh','unten','vorne');`);
    my sensorrohre = JoinList(klapprohre,ausziehrohre);
    for (my rohr : sensorrohre) {
      if ( Bool(call amountVerbraucher(rohr,'weiss')) ) {
        conflicts = ListAdd(conflicts, rohr);
        break;
      }
    }
    return conflicts;
    }

