def nochmalsTrennenE() {
    my conflicts = List(); 
    my kugel = null;
    my rohre = List();
    my leitenderohre = List();
    my leitenderohregetrennt = List();
    my getrenntkeinschlitz = List();
    my checklisterohre = List();
    my getrenntverbraucher = List();
    my dockliste = List();    
    rohre = GetComponentListOfType('normalrohr');
    leitenderohre = FilterList(rohre,'element',`Feature(element,'f_rohrtyp') ne 'rohr-leitend';`);
    leitenderohregetrennt = FilterList(leitenderohre,'element',`Feature(element,'mid') ne '0';`);
    /* 250er,395er Rohre ohne Schlitz */
    getrenntkeinschlitz = FilterList(leitenderohregetrennt,'element',`Feature(element,'Schlitz');`);
    /* 350er,500er,750er Rohre leitend mit Schlitz*/
    getrenntverbraucher = FilterList(leitenderohregetrennt,'element',`my len = PartAttr(element,'hc_length'); not (len ge 350 and StringContains(len,'50'));`);
    checklisterohre = JoinList(getrenntkeinschlitz,getrenntverbraucher);
    for (my rohr : UniqueList(checklisterohre)) {
      dockliste = List(Dock(rohr,'rohr2kugel',1),Dock(rohr,'rohr2kugel',2));
      for (my dock : dockliste) {
        kugel = DockGetConnectedPart(dock);
        if (kugel) {
          if (Feature(kugel,'f_kugelLeitend') AND !InList(conflicts,rohr)) {
            conflicts = ListAdd(conflicts, rohr);
            break;
          }
        }
      }
    }
    return conflicts;
    }

