def stromkreisKreuzKugel() {
    my conflicts = List(); 
    my stromkreis = '';
    my stromkreise = List(0,0,0,0);
    my rohre = List();
    my size = 0;
    my number = 0;
    my kugelinfo = List();    
    my kugeln = GetComponentListOfType('kugel_std');
    my ekugeln = FilterList(kugeln,'element',`not Feature(element,'f_kugelLeitend');`);
    for (my ekugel : ekugeln) {
      kugelinfo = call isKugelLeitend(ekugel);
      stromkreise = List(0,0,0,0);
      rohre = kugelinfo[1];
      size = Size(rohre);
      if (size ge 4) {
        /* stromkreis = Feature(rohre[0],'f_stromkreis'); */
        /* die Rohre werden nun auf den Stromkreis ueberprueft */
        for (my rohr : rohre) {
         stromkreis = Feature(rohr,'f_stromkreis');
         number = Number(SubStr(stromkreis,11));
         stromkreise[number] = stromkreise[number] + 1;
        }
        /* wenn 2 Stromkreise zwei Rohre haben */
        if ((stromkreise[1] ge 2 and stromkreise[2] ge 2) or (stromkreise[1] ge 2 and stromkreise[3] ge 2) or
             (stromkreise[2] ge 2 and stromkreise[3] ge 2)   ) {
          conflicts = ListAdd(conflicts, ekugel);
        }
      }
    }
    return conflicts;
  }

