	};

def isKugelLeitend(part) {
    my leitend = List();
    leitend[0] = false;
    leitend[1] = List();
    my rohr = null;
    my leitenderohre = List();
    my size = 0;
    my number = 0;
    my stromkreise = List(0,0,0,0); /* 0 = dummy, stromkreis 1,2,3 */
    my einspeisung = Feature(part,'f_kugelEinspeisung');
    my dock1 = Dock('kugel2rohr',1);
    my dock2 = Dock('kugel2rohr',2);
    my dock3 = Dock('kugel2rohr',3);
    my dock4 = Dock('kugel2rohr',4);
    my dock5 = Dock('kugel2rohr',5);
    my dock6 = Dock('kugel2rohr',6);
    my docklist = List(dock1,dock2,dock3,dock4,dock5,dock6);
    for (my dock : docklist) {
      rohr = DockGetConnectedPart(dock);    
      if (rohr and IsSubTypeOf(rohr,'normalrohr')) {
         /* Message(GetTypeName(rohr) ++ ', ' ++ GetDockType(docklist[i]) ++ DockGetIndex(docklist[i])); */
         if (Feature(rohr,'f_rohrtyp') ne 'rohr-normal') {
           leitenderohre = ListAdd(leitenderohre,rohr);
        }
      }
    }
    size = Size(leitenderohre);
    if (size gt 1) {
      for (my rohr : leitenderohre) {
        number = SubStr(Feature(rohr,'f_stromkreis'),11);
        stromkreise[number] = stromkreise[number] + 1;
      }
      leitend[0] = ListMax(stromkreise) ge 2; /* mindestens 2 leitende Rohre muessen denselben Stromkreis haben */
      if (leitend[0]) {
        for (my i : IndexList(stromkreise)) {
           if (stromkreise[i] gt stromkreise[0]) {
              stromkreise[i] = stromkreise[0];
           }
        }
      }
    }
    leitend[0] =  leitend[0] or
                  einspeisung or 
                 (Feature(part,'f_hallerExtendedE') and Size(leitenderohre) ge 1);
    leitend[1] = leitenderohre;
    leitend[2] = 'stromkreis-' ++ stromkreise[0];
    return leitend;
    }

