	  eparts = FilterList(eparts,'element',`Feature(element,'f_stromkreis') ne stromkreis;`);
	  return eparts;
	}

def stromkreisMissingTrafo() {
    my conflicts = List();
    my kugeln = GetComponentListOfType('kugel_std');
    my ekugeln = FilterList(kugeln,'element',`not Feature(element,'f_kugelLeitend');`);
    my stromkreis = List();
    my stromkreis1 = false;
    my stromkreis2 = false;
    my stromkreis3 = false;
    my stromkreise = List();
    my group = List();
    my groups = call groupByConnectionIds(ekugeln);
    for (my i : IndexList(Size(groups))) {
       group = groups[i];
       stromkreis = FilterList(group,'element',`Feature(element,'f_stromkreis') ne 'stromkreis-1';`);
       if (Size(stromkreis)) {
         stromkreise[i]['stromkreis1'] = false;
         for (my ekugel : stromkreis) {
            if (Feature(ekugel,'f_kugelEinspeisung')) {
              stromkreise[i]['stromkreis1'] = true;
              break;
            }
         }
       } else {
           stromkreise[i]['stromkreis1'] = true;
       }
       stromkreis = FilterList(group,'element',`Feature(element,'f_stromkreis') ne 'stromkreis-2';`);
       if (Size(stromkreis)) {
	       stromkreise[i]['stromkreis2'] = false;
	       for (my ekugel : stromkreis) {
	          if (Feature(ekugel,'f_kugelEinspeisung')) {
	            stromkreise[i]['stromkreis2'] = true;
	            break;
	          }
	       }
       } else {
           stromkreise[i]['stromkreis2'] = true;
       }
       stromkreis = FilterList(group,'element',`Feature(element,'f_stromkreis') ne 'stromkreis-3';`);
       if (Size(stromkreis)) {
	       stromkreise[i]['stromkreis3'] = false;
	       for (my ekugel : stromkreis) {
	          if (Feature(ekugel,'f_kugelEinspeisung')) {
	            stromkreise[i]['stromkreis3'] = true;
	            break;
	          }
	       }
       } else {
           stromkreise[i]['stromkreis3'] = true;
       }
       if (not stromkreise[i]['stromkreis1'] or not stromkreise[i]['stromkreis2'] or not stromkreise[i]['stromkreis3'] ) {
         conflicts = ListAdd(conflicts,group[0]);
       }
    }
  return conflicts;
  }

def groupByConnectionIds(elements) {
     my list = List();
     my subList = List();
     elements = Sort(elements,`my c1 = ConnectionId(element1); my c2 = ConnectionId(element2); c1 gt c2 ? 1 : (c1 lt c2 ? -1 : 0);`);
     my lastId = -1;
     my connectionId = '0';
     for (my element : elements) {
       connectionId = ConnectionId(element);
       if (connectionId ne lastId) {
         lastId = connectionId;
         subList = List();
         ListAdd(list, subList);
       }
       ListAdd(subList, element);
     }
     return list;
   }

