def stromSpannungEU(part) {
    my spannung = true;
    part = ChildWithId(part,'10');
    my featurelist = List();
    my value = '';
    my amount = '';
    if (part) {
      featurelist = List('f_verbraucherL','f_verbraucherM','f_verbraucherR');
      for (my feature : featurelist) {
        if (HasFeature(part, feature)) {
          value = Feature(part,feature);
          if (value eq einsatz) {
            amount = amount + 1;
          }
        }
      } 
    }
    return amount;
  }

def amountVerbraucher(part,einsatz) {
    my amount = 0;
    my featurelist = List();
    my value = '';
    my child = null;
    if (part) {
      child = ChildWithId(part,'10');
      if (child) {
        /* Artikel Structure */
        part = child;
      }
      featurelist = List('f_verbraucherL','f_verbraucherM','f_verbraucherR');
      for (my feature : featurelist) {
        if (HasFeature(part, feature)) {
          value = Feature(part,feature);
          if (EndsWith(value,einsatz)) {
            amount = amount + 1;
          }
        }
      } 
    }
    return amount;
  }


