def stromkreisEnde(part,mode) {

    my connectors = 0;
    my endecheck = List();
    my seiten = List();
    my kugel = null;
    my kugelleitend = false;
    my rohrtype = '';
    my gewrohr = false;
    my normalrohr = false;
    my nextrohr = null;
    my hilfsrohrliste = List();
    my dockliste = List();
    my hilfsdockliste = List();
    my leitenderohre = List();
    my connectorsNormal = List();
    my connectorsLeitend = List();
    my connectorsIsolierend = List();
    my stromkreis = '';
    my stromkreise = List();
    if ( EndsWith(mode,'Artikel')) {
     part = ChildWithId(part,'10');
    }
    if (part) {

      rohrtype = GetTypeName(part);
      gewrohr = BeginsWith(rohrtype,'gewrohr');
      stromkreis = Feature(part,'f_stromkreis');
      normalrohr = Feature(part,'f_rohrtyp') eq 'rohr-normal' or gewrohr;
      dockliste = List(
      		Dock(part,'rohr2kugel',1),
      		Dock(part,'rohr2kugel',2),
      		Dock(part,'rohr2gewinde_90',1),
      		Dock(part,'rohr2gewinde_90',2),
      		Dock(part,'rohr2gewinde_180',1),
      		Dock(part,'rohr2gewinde_180',2)
      		);
      if (gewrohr) {
         hilfsrohrliste = List(DockGetConnectedPart(Dock(part,'kugel2rohr',1)),DockGetConnectedPart(Dock(part,'kugel2rohr',2)));
         for (my hilfsrohr : hilfsrohrliste) {
            hilfsdockliste = ListAdd(hilfsdockliste,Dock(hilfsrohr,'rohr2kugel',1));
            hilfsdockliste = ListAdd(hilfsdockliste,Dock(hilfsrohr,'rohr2kugel',2));
         }
         dockliste = FilterList(hilfsdockliste,'element',`not IsSubTypeOf(DockGetConnectedPart(element),'kugel_std');`);
      }   
      for (my rohrdock : dockliste) {
        leitenderohre = List();
        stromkreise = List();
        kugel = DockGetConnectedPart(rohrdock);
        if (kugel) {
          kugelleitend = Feature(kugel,'f_kugelLeitend');
          if (kugelleitend) {
            if (normalrohr) {
              connectorsIsolierend = ListAdd(connectorsIsolierend, kugel);
            } else {
              if (not Feature(kugel,'f_kugelEinspeisung')) {
                for (my index : List(1,2,3,4,5,6)) {
                  nextrohr = DockGetConnectedPart(Dock(kugel,'kugel2rohr',index));
                  if (nextrohr and nextrohr ne part) {
                    if (Feature(nextrohr,'f_rohrtyp') ne 'rohr-normal') {
                      leitenderohre = ListAdd(leitenderohre,nextrohr);
                      stromkreise = ListAdd(stromkreise,Feature(nextrohr,'f_stromkreis'));
                    }
                  }
                }
                if (Size(leitenderohre)) {
                  stromkreis = Feature(part,'f_stromkreis');
                  /* hat 1 Leitendes Rohr VisVis */
                  if (Size(leitenderohre) eq 1) {
                    if (stromkreise[0] eq stromkreis) {
                      /* Stromkreis geht weiter */
                      connectorsLeitend = ListAdd(connectorsLeitend, kugel);
                    } else {
                      /* Stromkreis geht nicht weiter, sondern ein anderer beginnt */
                      /* sollte eigentlich schon abgefangen sein das normale Kugel */
                      /* im Extende Modus jedoch ist diese Kugel leitend */
                      if (Feature(part,'f_stromkreis') eq Feature(kugel,'f_stromkreis')) {
                         /* im Extende Modus, wenn Rohr gleicher Stromkreis wie Kugel */
                        connectorsLeitend = ListAdd(connectorsLeitend,kugel);
                      } else {
                        /* im Extende Modus, wenn Rohr anderer Stromkreis wie Kugel */
                        connectorsIsolierend = ListAdd(connectorsIsolierend,kugel);
                      }
                    }
                  } else if (Size(leitenderohre) eq 2) {
                    if ( InList(stromkreise,stromkreis ) ) {
                      connectorsLeitend = ListAdd(connectorsLeitend,kugel);
                    } else {
                      connectorsIsolierend = ListAdd(connectorsIsolierend, kugel);
                    }  
                  } else if (Size(leitenderohre) gt 2) { 
                    if (call leitendeConnectorKreuz(stromkreis,leitenderohre)) {
                      connectorsLeitend = ListAdd(connectorsLeitend,kugel);
                    } else {
                      connectorsIsolierend = ListAdd(connectorsIsolierend, kugel);
                    }
                  } 
                } else {
                  /* Kugel ist leitend,aber kein anderes Rohr, zB im extend mod */
                    connectorsLeitend = ListAdd(connectorsLeitend,kugel);
                }
              } else {
                /* Kugel ist Einspeisekugel */
                connectorsLeitend = ListAdd(connectorsLeitend, kugel);
              } 
            }       
          } else {
            /* Kugel ist Normale Kugel */
            connectorsNormal = ListAdd(connectorsNormal,kugel);
          }
        }
      }
    }
    if ( BeginsWith(mode,'Normal')) {
      connectors = Size(connectorsNormal); /* anzahl Normal Connectors */
    } else if ( BeginsWith(mode,'Leitend')) {
      connectors = Size(connectorsLeitend); 
    } else if ( BeginsWith(mode,'Isolierend')) {
      connectors = Size(connectorsIsolierend); 
    } 
    return connectors;
  }

def connectionReCalculation(part) {
    my valid = List();
    my shortestpath = List();
    my connected = true;
    my unterbruch = List();
    my kugelL = null;
    my kugelR = null;
    my tube = null;
    my nextkugel = null;
    my valid = true;
    my leitendL = false;
    my leitendR = false;
    my connection = List();
    my connections= List();
    my rohre = call stromkreisRohrList(part);
    my kugeln = call stromkreisKugelList(part);
    my count = 0;
    my start = '';
    my weight = 0;
    my stromkreis = Feature(part,'f_stromkreis');
    my stromkreisL = false;
    my stromkreisR = false;
    my einspeisung = FindPart(part,'kugel_std');
    if (einspeisung) {
      einspeisung = PartUniqueId(einspeisung);
      for (my rohr : rohre) {
        /* generieren der Verbindungspaare (connections) */
        kugelL = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
        kugelR = DockGetConnectedPart(Dock(rohr,'rohr2kugel',2));
        weight = PartAttr(rohr,'hc_length');
        if (kugelL and kugelR) {
          stromkreisL = Feature(kugelL,'f_stromkreis') eq stromkreis;
          stromkreisR = Feature(kugelR,'f_stromkreis') eq stromkreis;
          leitendL = Feature(kugelL,'f_kugelLeitend');
          leitendR = Feature(kugelR,'f_kugelLeitend');          
          /* mindestens eine Kugel muss leitend sein und den richtigen Stromkreis besitzen */
          /* sonst ist das Rohr nicht verbunden und kommt somit nicht in die Berechnung des shortestPath mit rein*/   
          if ((leitendL and stromkreisL) or (leitendR and stromkreisR)) {
           /* von links nach rechts */
           connection = List(PartUniqueId(kugelL),PartUniqueId(kugelR),weight);
           connections[count] = connection;
           count = count + 1;
           /* von rechts nach links */
           connection = List(PartUniqueId(kugelR),PartUniqueId(kugelL),weight);
           connections[count] = connection;
           count = count + 1;
          } else {
             /* es gibt ein Rohr, das keine leitende Kugel angeschlossen hat */
             connected = false;
             unterbruch = ListAdd(unterbruch,rohr);
             break;

          }
        }
      }
      /* Falls Rohr ohne leitende Kugeln Shortest Path muss gar nicht gerechnet werden */
      if (connected) {    
        for (my kugel : kugeln) {
          /* es muss von jeder Kugel aus einen path geben, sonst ist der Stromkreis unterbrochen */
          start = PartUniqueId(kugel);
          shortestpath = ShortestPath(connections, start, einspeisung);
          if (Size(shortestpath[0][1]) eq 0) {
             connected = false;
             unterbruch = ListAdd(unterbruch,kugel);
             for (my index : List('1','2','3','4','5','6')){
               tube = DockGetConnectedPart(Dock(kugel,'kugel2rohr',index));
               if (tube) {
                 if (Feature(tube,'f_rohrtyp') ne 'rohr-normal'){
                   for (my i : List('1','2')) {
                     nextkugel = DockGetConnectedPart(Dock(tube,'rohr2kugel',i)); 
                     if (nextkugel) {    
                       if (not Feature(nextkugel,'f_kugelLeitend')){
                         unterbruch = ListAdd(unterbruch,tube);
                         break;
                       }
                     }
                   }
                 }
               }
             }
          }
        }
      }
    } else {
      connected = false;
      unterbruch = ListAdd(unterbruch,part);
    }
    valid[0] = connected;
    valid[1] = unterbruch;
   return valid;  
  }

def rohrEndeKugelE(part,artikel) {
    my count = 0;
    my kugel = null;
    if (artikel eq 'connectorArtikel') {
      part = ChildWithId(part,'10');
    }
    for (my i : List(1,2)) {
       kugel = DockGetConnectedPart(Dock(part,'rohr2kugel',i));
       if (Feature(kugel,'f_kugelLeitend')) {
         count = count + 1;
       }
    }
   return count;
  }

def extendedModeHallerE(rohreE) {
    my extendedrohre = List();
    my rohre = FilterList(rohreE,'element',`Feature(element,'f_rohrtyp') ne 'rohr-verbraucher';`);
    my normalrohre = FilterList(rohreE,'element',`Feature(element,'f_rohrtyp') ne 'rohr-normal';`);
    my reldist = Vector();
    my position_z = List();
    my posz = List();
    for (my rohr : rohre) {
     for (my normal : normalrohre) {
       reldist = RelativePartPos(rohr, normal);
       if ( Round(reldist['x']) eq 0 and Round(reldist['z']) eq 0) {
         extendedrohre = ListAdd(extendedrohre,normal);
       }
     }
   }
   return extendedrohre;
   }

def defaultEinspeisung(fixedpart,eparts) {
    my einspeisung = null;
    my found = false;
    my rohr = null;
    my visavi = null;
    my foundedlist = List();
    my connectedparts = List();
    my connectedrohre = List();
    my rohre = FilterList(eparts,'element',`not IsSubTypeOf(element,'normalrohr');`);
    rohre = FilterList(rohre,'element',`not call horizontalPart(element);`);
    visavi = call visaviRohr(fixedpart,rohre);
    /* Position visavi markiere */
    my x = Round(PartPos(visavi)['x']);
    my y = Round(PartPos(visavi)['y']);
    /* alle Horizotal-Rohre unten */
    rohre = FilterList(rohre,'element',`Round(PartPos(element)['z']) ge 3.5;`);
    /* das Rohr unten suchen mit der gleichen Position */
    foundedlist = FilterList(rohre,'element',`Round(PartPos(element)['x']) ne x or Round(PartPos(element)['y']) ne y;`);
    rohr = foundedlist[0];

    if (rohr) {
      einspeisung = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
      if (einspeisung) {
        if (ConnectedDockCount(einspeisung,'kugel2rohr') ge 5) {
          x = Round(PartPos(fixedpart)['x']);
          y = Round(PartPos(fixedpart)['y']);
          foundedlist = FilterList(rohre,'element',`Round(PartPos(element)['x']) ne x or Round(PartPos(element)['y']) ne y;`);
          rohr = foundedlist[0];
          if (rohr) {
            einspeisung = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
           connectedparts = call connectedPartsByDockType(einspeisung,'kugel2rohr');
           connectedrohre = FilterList(connectedparts,'element',`not IsSubTypeOf(element,'rohr');`);
            if (Size(connectedrohre) ge 5) {
              einspeisung = null;
            }
          }
        }
      }
    }
    return einspeisung;
  }

def nextKugel(rohr,kugel,found,count) {
    my newkugel = null;
    my newrohr = null;
    my dock = null;
    if (count lt 3) {
	    if (not found) {
	      for (my index : List(1,2,3,4,5,6)) {
	        dock = Dock(kugel,'kugel2rohr',index);
	        newrohr = DockGetConnectedPart(dock);
	        if (newrohr and (newrohr ne rohr)) {
	          newkugel = DockGetConnectedPart(Dock(newrohr,'rohr2kugel',1));
	          if (newkugel) {
	            if (newkugel ne kugel) {
	              if (ConnectedDockCount(kugel,'kugel2rohr') lt 4) {
	                found = true;
	              } 
	            } else {
	              newkugel = DockGetConnectedPart(Dock(newrohr,'rohr2kugel',2));
	              if (newkugel ne kugel) {
	                if (ConnectedDockCount(kugel,'kugel2rohr') lt 4) {
	                  found = true;
	                } 
	              }
	            }
	          } 
	        }
	        if (found) {
	         break;
	        }
	      }   

	    } 
	    if (not found) {
	      rohr = newrohr;
	      count = count + 1;
	      kugel = call nextKugel(rohr,newkugel,found,count);
	    }
    }

  return newkugel;
  }

def visaviRohrVertikal(part,vertikalrohre) {
    my visavi = false;
    my visavix = null;
    my visaviz = null;
    my distx = 0;
    my pos = Vector();
    my partners = List();
     /* 1/4 der Rohrlaenge + 1 wegen 350er Rohr und visavi 2x175 Rohre */
    my offset = (PartAttr(part,'hc_length')/10/4) +1;



    vertikalrohre = FilterList(vertikalrohre,'element',`my rel = RelativePartPos(part, element);Round(Abs(rel['y']) gt offset);`);
    partners = FilterList(vertikalrohre,'element',`part eq element;`);
    my distz = 0;
    my distmin = 99999;
    for (my partner : partners) {
       pos = RelativePartPos(part, partner);
       distx = Round(pos['x']);
       distz = Round(pos['z']);
       if (distz lt distmin and distz and not distx) {
           distmin = distz;
           visaviz = partner;
       }
    }

    distx = 0;
    distmin = 99999;
    for (my partner : partners) {
       pos = RelativePartPos(part, partner);
       distx = Round(pos['x']);
       distz = Round(pos['z']);
       if (distx lt distmin and distx and not distz) {
           distmin = distx;
           visavix = partner;
       }
    }
    visavi = Bool(visavix) and Bool(visaviz);
    return visavi;
  }

def visaviRohr(part,horizontalerohre) {
	my visavi = null;
	my partners = List();
	/* 1/4 der Rohrlaenge + 1 wegen 350er Rohr und visavi 2x175 Rohre */
	my offset = (PartAttr(part,'hc_length')/10/4) +1; 
	my basicOffset = 75;
	my boundingBoxOffset = 3;
	my finalOffset = basicOffset + boundingBoxOffset;
	horizontalerohre = FilterList(horizontalerohre,'element',`my dist = call rohreAreParallelAndDistance(part, element); not (dist gt 0 and dist lt finalOffset);`);
	partners = FilterList(horizontalerohre,'element',`Round(PartPos(element)['z']) ne Round(PartPos(part)['z']);`);
	partners = FilterList(partners,'element',`part eq element;`);
	my dist = 0;
	my distmin = 99999;

	my seg1 = Segment(GlobalDockPos(Dock(part, 'rohr2kugel',1),Vector()),GlobalDockPos(Dock(part, 'rohr2kugel',2),Vector()));
	for (my partner : partners) {
		dist = Round(SegmentPointDistance(seg1, PartPos(partner)), 0.001);
		if (Round(dist, 0.1) eq dist) {
			visavi = partner;
		}
	}
	return visavi;
  }

def rohreAreParallel(rohr, otherrohr) {
    my result = false;
    if (rohr and otherrohr) {
	    my rohr_d1 = Dock(rohr, 'dt_rohrKugelGewinde', 1);
	    my rohr_d2 = Dock(rohr, 'dt_rohrKugelGewinde', 2);
	    my otherrohr_d1 = Dock(otherrohr, 'dt_rohrKugelGewinde', 1);
	    my otherrohr_d2 = Dock(otherrohr, 'dt_rohrKugelGewinde', 2);

	    my line1 = Line(GlobalDockPos(rohr_d1, Vector()), VectorSub(GlobalDockPos(rohr_d2, Vector()), GlobalDockPos(rohr_d1, Vector()))); 	
	    my line2 = Line(GlobalDockPos(otherrohr_d1, Vector()), VectorSub(GlobalDockPos(otherrohr_d2, Vector()), GlobalDockPos(otherrohr_d1, Vector()))); 	

	    result = LinesAreParallel(line1, line2);

    };

    return result;
  }

def rohreAreParallelAndDistance(rohr, otherrohr) {
	my result = 0;
	my maxExtendedRohrLength = 84; //rohr max: 75 + bounding box rotated max: 9
	if (rohr and otherrohr) {
		my rohr_d1 = Dock(rohr, 'dt_rohrKugelGewinde', 1);
		my rohr_d2 = Dock(rohr, 'dt_rohrKugelGewinde', 2);
		my otherrohr_d1 = Dock(otherrohr, 'dt_rohrKugelGewinde', 1);
		my otherrohr_d2 = Dock(otherrohr, 'dt_rohrKugelGewinde', 2);

		my line1 = Line(GlobalDockPos(rohr_d1, Vector()), VectorSub(GlobalDockPos(rohr_d2, Vector()), GlobalDockPos(rohr_d1, Vector()))); 	
		my line2 = Line(GlobalDockPos(otherrohr_d1, Vector()), VectorSub(GlobalDockPos(otherrohr_d2, Vector()), GlobalDockPos(otherrohr_d1, Vector()))); 	

		if (LinesAreParallel(line1, line2)) {
			/* check x and y extent within max rohr 75 */
			my extent = GlobalBoundingBox(List(rohr, otherrohr), 1000)['extent'];
			if (Round(extent['x'] LT maxExtendedRohrLength and Round(extent['y'] LT maxExtendedRohrLength))) {
				result = Round(LineDistance(line1, line2));
			}
		}
	}
	return result;
  }

def leitendeRohre(startpart,einspeisung,eparts) {
    my path = List();
    my leistung = Feature(startpart,'f_verbraucherLeistung');
    my stromkreis = Feature(startpart,'f_stromkreis');
    my verbraucherrohre = List();
    my shortestpath = List();
    einspeisung = PartUniqueId(einspeisung);
    my start = DockGetConnectedPart(Dock(startpart,'rohr2kugel',2));
    start = PartUniqueId(start);
    my kugeln = FilterList(eparts,'element',`not IsSubTypeOf(element,'kugel');`);
    my rohre = FilterList(eparts,'element',`not IsSubTypeOf(element,'normalrohr');`);
    my kugel = null;
    my endkugel = null;
    my kugelpath = List();
    my nodepath = List();
    my rohr = null;
    my weight = 0;
    my connection = List();
    my connections= List();
    my link = List();
    my links = List();
    my count = 0;
    for (my kugel : kugeln) {
        connection = List();
        for (my j : IndexList(7)) {
          rohr = DockGetConnectedPart(Dock(kugel,'kugel2rohr',j));
          if (Bool(rohr)) {
             /* Rohrlaenge + je hoeher desto schwerer, d.h. d.h. rohre unten sind kuerzer/schneller */
             weight = PartAttr(rohr,'hc_length') + PartPos(rohr)['z'];
             if (weight le 150) {
               weight = 99999; /* 100/150er Rohre */
             }
             if (call snapHallerEtoKugelStift(rohr)) {
                weight = 99999;
             }
             if (Feature(rohr,'f_rohrtyp') ne 'rohr-normal') {
                weight = 0;
             }
             if (Feature(rohr,'f_rohrtyp') ne 'rohr-normal' and Feature(rohr,'f_stromkreis') ne stromkreis) {
                /* damit bestehende andere Stromkreise nicht ueberschrieben werden */
                weight = 99999;
             }
             endkugel = DockGetConnectedPart(Dock(rohr,'rohr2kugel',1));
             if (endkugel eq kugel) {
                endkugel = DockGetConnectedPart(Dock(rohr,'rohr2kugel',2));
             }
             if (Bool(endkugel)) {
              if (Feature(kugel,'f_stromkreis') ne stromkreis and Bool(Feature(kugel,'f_kugelLeitend')) or 
                  Feature(endkugel,'f_stromkreis') ne stromkreis and Bool(Feature(endkugel,'f_kugelLeitend'))) {
                  weight = 99999;
              }
              connection = List(PartUniqueId(kugel),PartUniqueId(endkugel),weight);
              connections[count] = connection;
              count = count + 1;
              rohr = null;
              endkugel = null;
             }
          }
        }
    }  
    shortestpath = ShortestPath(connections, start, einspeisung);
    nodepath = shortestpath[0][1];
    /* shortest Path Kugel componentlist */
    for (my i = 0; i lt Size(nodepath); i = i + 1) {
       kugelpath[i] = FindComponentById(nodepath[i]);
    }
    path[0] = kugelpath; /* alle Kugeln */
    path[1] = call rohrpath(kugelpath); /* alle Rohre */
    /* es werden nur Rohre neu gesetzt, die keine verbraucher sind */
    path[2] = FilterList(path[1],'element',`Feature(element,'f_rohrtyp') eq 'rohr-verbraucher';`);
    /* nur leitende im getrennten Bereich */
    path[3] = FilterList(path[2],'element',`Feature(element,'f_rohrtyp') ne 'rohr-normal' and Feature(element,'mid' ne '0');`); 
    path[3] = FilterList(path[3],'element',`my len = PartAttr(element,'hc_length'); not (len ge 350 and StringContains(len,'50'));`); 

     /* nur normal Rohre */
    path[4] = FilterList(path[2],'element',`Feature(element,'f_rohrtyp') eq 'rohr-leitend';`);
    /* Stromkreis setzen*/
    path[5] = JoinList(path[0],path[1]);
    return path;
  }

def rohrpath(kugelpath) {
    my path = List();
    my nextrohr = null;
    my dock = null;
    my nextdock = null;
    my dockindex = 1;
    my kugel = null;
    my searchkugel = null;
    my nextkugel = null;
    my found = false;
    for (my i : IndexList(Size(kugelpath)-1)) {
    kugel = kugelpath[i];
    searchkugel = kugelpath[i+1];
    found = false;
    for (my index : List(1,2,3,4,5,6)) {
      dock = Dock(kugel,'kugel2rohr',index);
       nextdock = DockGetConnectedDock(dock);
       if (nextdock) {
         nextrohr = DockGetConnectedPart(dock);
         dockindex = DockGetIndex(nextdock);
         if (dockindex eq 1) {
           dockindex = 2;
         } else {
           dockindex = 1;
         } 
         nextkugel = DockGetConnectedPart(Dock(nextrohr,'rohr2kugel',dockindex));
         if (nextkugel eq searchkugel) {
           path = ListAdd(path,nextrohr);
           found = true;
           break;
         }
       }
      }
      if (found) {
        i = i +1;
      }
    }
    return path;
    }

def separateHallerE(mode) {
    my setlist = List();
    my list = List();
    my list2 = List();
    my kugel = null;
    if (mode eq 'verbraucher') {
      list = GetSelectedComponentList('mainstructure');
      list = FilterList(list,'element',`not Feature(element,'f_hallerE');`);
      /* 350/500/750er Rohre */
      list = FilterList(list,'element',`not IsSubTypeOf(element,'ct_verbraucherRohrE');`);
      /* nur leitende Rohre */
      setlist = FilterList(list,'element',`Feature(element,'f_rohrtyp') ne 'rohr-leitend';`);
      /* nur leitende Rohre im Trennbereich*/
      setlist = FilterList(setlist,'element',`Feature(element,'mid') ne '0';`);
      /* normale Rohre */
      list2 = FilterList(list,'element',`Feature(element,'f_rohrtyp') ne 'rohr-normal';`);
      list2 = FilterList(list2,'element',`Bool(ParentOfType(element, 'mainstructure', 'garderobenstange'));`);
       /* nur normale Rohre im Trennbereich*/
      list2 = FilterList(list2,'element',`Feature(element,'mid') ne '0';`);
      /* normale Rohre angrenzend an e-Kugel */
      for (my rohr : list2) {
        for (my i : List(1,2)) {
          kugel = DockGetConnectedPart(Dock(rohr,'rohr2kugel',i));
            if (kugel) {
            if (Feature(kugel,'f_kugelLeitend')) {
              /* wird zur setlist der durchgehenden leitenden Rohre addiert */
              setlist = ListAdd(setlist, rohr);
              break;
            }
          }
        }
      }
      /* Message(list); */
    } else if (mode eq 'leitend') {
      list = GetSelectedComponentList('mainstructure');
      list = FilterList(list,'element',`not IsSubTypeOf(element,'normalrohr');`);
      list = FilterList(list,'element',`Feature(element,'mid') ne '0';`);
      list = FilterList(list,'element',`Feature(element,'f_rohrtyp') ne 'rohr-normal';`);
      list = FilterList(list,'element',`Bool(ParentOfType(element, 'mainstructure', 'garderobenstange'));`);
      list = FilterList(list,'element',`not (PartAttr(element,'hc_length') eq '395' or PartAttr(element,'hc_length') eq '250');`);
      for (my rohr : list) {
        for (my i : List(1,2)) {
          kugel = DockGetConnectedPart(Dock(rohr,'rohr2kugel',i));
          if (kugel) {
            if (Feature(kugel,'f_kugelLeitend')) {
              setlist = ListAdd(setlist, rohr);
              break;
            }
          }
        }
      }
    }
    return setlist;
    }

def joinHallerE(mode) {
    my setlist = List();
    my leitendlist = List();
    my list = GetSelectedComponentList('mainstructure');
    list = FilterList(list,'element',`not Feature(element,'f_hallerE');`);
    /* list = FilterList(list,'element',`Feature(element,'_PXi_permanent_group_id') ne groupid;`); */
    if (mode eq 'verbraucher') {
	    /* 350/500/750er Rohre */
	    setlist = FilterList(list,'element',`not IsSubTypeOf(element,'ct_verbraucherRohrE');`);
	    /* nur verbraucher Rohre */
	    setlist = FilterList(setlist,'element',`Feature(element,'f_rohrtyp') ne 'rohr-verbraucher';`);
	    /* nur Rohre im Trennbereich*/
	    setlist = FilterList(setlist,'element',`Feature(element,'mid') ne '0';`);
	    /* nur Rohre mit ausschliesslich dummy_verbraucher*/
	    setlist = FilterList(setlist,'element',`call verbraucherEinsatzTypen(element,'usb') gt 0;`);
	    setlist = FilterList(setlist,'element',`call verbraucherEinsatzTypen(element,'led') gt 0;`);
    } else if (mode eq 'leitend') {
	    /* leitende Rohre */
	    leitendlist = FilterList(list,'element',`Feature(element,'f_rohrtyp') ne 'rohr-leitend';`);
	    /* nur Rohre im Trennbereich*/
	    leitendlist = FilterList(leitendlist,'element',`Feature(element,'mid') ne '0';`);
	    for (my rohr : leitendlist) {
	      if (call rohrEndeKugelE(rohr,'component') eq 1) {
	        setlist = ListAdd(setlist, rohr);
	      }
	    }
    }

    return setlist; 
    }

def trafoTypeE(part) {
    my type = 'CH/EU'; 
    my model = Feature(part,'f_trafoModell'); 

    if (not EndsWith(model,'eu')) {
      if (EndsWith(model,'au_nz')) {
        my temp = StringToList(UpperCase(SubStr(model,7,5)),'_');
        type = temp[0]++'/'++temp[1];
      } else {
        type = UpperCase(SubStr(model,7,2));
      }
    }    
    return type; 
    }

def rohrBefestigung(part) {
    my default = 'rohr-ohne-Loch';
    if (PartAttr(part,'hc_length') eq '750') {
	    my loch = Feature(part,'Loch');
	    my glas = call verbraucherHorizontalVerkleidung(part,'glas');
	    my richtung = Feature(part,'f_rohrRichtung');
	    if (loch and not glas) {
	      default = 'rohr-mit-Loch';
	      if (richtung eq 'richtung-oben-180' or richtung eq 'richtung-aussen-270') {
	        default = 'rohr-mit-sicherungswinkel';
	      }
	    }
    }
    return default; 
    }

def posVolume(part,pos) {
    my vol = null;
    my volumes = GetRefVolumes(part, 'mainstructure');
    my partpos = PartPos(part);
    my boden = partpos['z'] lt 4;
    my posx = 0;
    my posy = 0;
    my posz = 0;
    my posx1 = 0;
    my posx2 = 0;
    my posx3 = 0;
    my posy1 = 0;
    my posy2 = 0;
    my posy3 = 0;
    my posz1 = 0;
    my posz2 = 0;
    my posz3 = 0;
    if (volumes[0]) {
      posx = Round(PartPos(volumes[0])['x']);
      posy = Round(PartPos(volumes[0])['y']);
      posz = Round(PartPos(volumes[0])['z']);
    }
    if (volumes[1]) {
      posx1 = Round(PartPos(volumes[1])['x']);
      posy1 = Round(PartPos(volumes[1])['y']);
      posz1 = Round(PartPos(volumes[1])['z']);
    }
     if (volumes[2]) {
      posx2 = Round(PartPos(volumes[2])['x']);
      posy2 = Round(PartPos(volumes[2])['y']);
      posz2 = Round(PartPos(volumes[2])['z']);
    }
     if (volumes[3]) {
      posx3 = Round(PartPos(volumes[3])['x']);
      posy3 = Round(PartPos(volumes[3])['y']);
      posz3 = Round(PartPos(volumes[3])['z']);
    }

    if (BeginsWith(pos,'unten')) {
      pos = Bool(volumes[0]);
      vol = volumes[0];

    } else if (BeginsWith(pos,'oben') and not boden) { 
      pos = Bool(volumes[1]) and posz1 gt posz;
      if (pos) {
        vol = volumes[1];
      } else {
         pos = Bool(volumes[2]) and posz2 gt posz;
         if (pos) {
           vol = volumes[2];
         }
      }

    } else if (BeginsWith(pos,'oben') and boden) { 
      vol = volumes[0];
    } else if (BeginsWith(pos,'seiteunten')) {
       pos = Bool(volumes[2]);
       if (pos) {
         vol = volumes[2];
       } else if (Bool(volumes[1]) and InRange(posz - 2, posz  + 2, posz1)) {
         vol = volumes[1];
       }
    } else if (BeginsWith(pos,'seiteoben')) {
      pos = Bool(volumes[3]);
      if (pos) {
        vol = volumes[1];
      }  
    }     
    return vol;
    }

def neuerStromKreis(fixedpart,movedpart) {
    my result = List();
    my new = true;
    my stromkreis_exist = Feature(fixedpart,'f_stromkreis');
    my stromkreis_next = stromkreis_exist;
    my stromkreis = stromkreis_exist;
    my eparts =GetComponentListOfConnectionId(ConnectionId(fixedpart));
    my rohre = FilterList(eparts,'element',`not IsSubTypeOf(element,'normalrohr');`);
    rohre = FilterList(rohre,'element',`Feature(element,'f_rohrtyp') eq 'rohr-nornal';`);
    my trafos = FilterList(eparts,'element',`not IsSubTypeOf(element,'co_trafo_E');`);
    my count_trafos = Size(trafos);
    my stromkreise_rohre = List();
    my stromkreise_trafos = List(); 
    my count_stromkreise_trafos = 0;
    for (my rohr : rohre) {
       my kreis = Feature(rohr,'f_stromkreis');
       if (not InList(stromkreise_rohre, kreis) and BeginsWith(kreis,'stromkreis-')) {
          stromkreise_rohre = ListAdd(stromkreise_rohre,kreis);
       }
    }
    for (my trafo : trafos) {
       my kreis = Feature(trafo,'f_stromkreis');
       if (not InList(stromkreise_trafos, kreis) and BeginsWith(kreis,'stromkreis-') and trafo ne movedpart) {
          stromkreise_trafos = ListAdd(stromkreise_trafos,kreis);
       }
    }
    stromkreise_rohre = Sort(stromkreise_rohre, 'StrAlphabeticalCompare(element1,element2);');
    stromkreise_trafos = Sort(stromkreise_trafos, 'StrAlphabeticalCompare(element1,element2);');
    count_stromkreise_trafos = Size(stromkreise_trafos);
    /* haben alle Rohr Stromkreise einen Trafo */
    for (my kreis : stromkreise_rohre) {
      if (not InList(stromkreise_trafos,kreis)) {
        /* wenn nicht, dann braucht es keinen neuen Stromkreis, sonder der Fehlende wird genommen */
        new = false;
        stromkreis = kreis;
        break;
      }
    }
    if (new and count_stromkreise_trafos lt 3 ) {
       /* alle Rohre haben Ihren Trafo, aber gibt es noch einen freien Stromkreis */
        for (my i : List(1,2,3)) {
          stromkreis_next = 'stromkreis-' ++ i;
          if (not InList(stromkreise_trafos,stromkreis_next)) {
            /* wenn nicht, dann ist das der naechste Stromkreis */
            stromkreis = stromkreis_next;
            break;
          }
        }
    } else {
       /* braucht eine neuen Stromkreis , es aber schon 3 */
       new = false;
    }
    result[0] = new;
    result[1] = stromkreis;
    result[2] = count_trafos le 3;
    return result;    
    }

def checkCleanUpHallerE(partE) {
    my changelist = List();
    my eparts = GetComponentListOfConnectionId(ConnectionId(partE));
    my rohre = FilterList(eparts,'element',`not IsSubTypeOf(element,'normalrohr');`);
    my leitenderohre = Bool(Size(FilterList(rohre,'element',`Feature(element,'f_rohrtyp') ne 'rohr-leitend';`)));
    my kugeln = FilterList(eparts,'element',`not IsSubTypeOf(element,'kugel_std');`);
    my leitendekugeln = Bool(Size(FilterList(kugeln,'element',`not Feature(element,'f_kugelLeitend');`)));
    if (not leitendekugeln and not leitenderohre) { 
       changelist = eparts;
    }

    return changelist; 
    }

def setHallerRohrEditE(mode,handlename) {
