def movedPartsHallerE(movedparts) {
    my list = List(); 
    my volumes = List();
    my movedpart = movedparts[0];
    my vol = null;
    my additional = null;
    my bleche = List();
    my auszuege = List();

    if (movedpart) {
      vol = ParentOfType(movedpart, 'mainstructure', 'normal_volume');

      if (vol) {
        if (Feature(vol,'f_volume_hallerE')) {
          list = movedparts;

          if (IsSubTypeOf(movedpart, 'schublade')) {
            additional = FindPart(movedpart,'schublade_l2schubladenauszug_l','1');
            if (additional) {
              list = ListAdd(list,additional);
            }
          }

          if (IsSubTypeOf(movedpart, 'einsatz')) {
            auszuege = ChildrenListOfTypeDeep(vol,'auszug500');
            if (Bool(Size(auszuege))) {
              list = JoinList(list,auszuege);
                additional = FindPart(auszuege[0],'auszug2rost');
            }

            if (additional) {
              list = ListAdd(list,additional);
              additional = FindPart(additional,'rost2regauszug');
            }

            if (additional) {
              list = ListAdd(list,additional);
            }

            bleche = GetVolumeRefParts(vol);
            bleche = FilterList(bleche, 'element',`not IsSubTypeOf(element, 'halbesblech395_500');`);
            additional = bleche[0];
            if (additional) {
              list = ListAdd(list,additional);
            }
          }
        }
      } else {
        volumes = GetRefVolumes(movedpart, 'mainstructure');
        if (Size(volumes)) {
          for (my vol : volumes) {

            if (Feature(vol,'f_volume_hallerE')) {
              list = movedparts;
              break;
            }
          }
        }
      }

    }
    return list;
  }

def verbraucherSituationT(part,typ) {
		my match = false;
		my dock = null;
		my localpos = Vector();
		my docktpos = Vector();
		my partvector_z = Vector();
		my dockvector_z = Vector();
		my part_z = '';
		my dock_z = '';
		my docktype = 'rohr2blech';
		my docks = List();
		my indexes = List();
		docks = FreeDocksOfType(part,docktype);

		if (typ eq 'blech') {
		if (Size(docks) eq 1) {
		  dock = docks[0];
		  localpos = Vector(0,0,-1);
		  docktpos = GlobalDockPos(dock,localpos);
		  partvector_z = LocalPos(part, VectorAdd(localpos, PartPos(part)));
		  dockvector_z = LocalDockPos(dock,docktpos);
		}
		part_z = partvector_z['z'];;
		dock_z = dockvector_z['z'];

		if (dock_z eq -1) {
		 match = true;
		}
		} else if (typ eq 'glas') {
		  /* es duerfen kein blechdocks besetzt sein */
		  if (Size(docks) eq 4 )  {
		   docktype = 'rohr2glashalter';
		   docks = FreeDocksOfType(part,docktype);
		   if (Size(docks) eq 2 )  {
		     indexes = ListAdd(indexes, DockGetIndex(docks[0]));
		     indexes = ListAdd(indexes, DockGetIndex(docks[1]));
		     if (InList(indexes,2) and InList(indexes,12)) {
		       match = true;
		     }
		   }
		  }
		}

		return match;
		}

