def snapHallerEtoKugelStift(target) {
		my kugel_stift = false;
		my list = List();
		my kugeldocks = ConnectedDocksOfType(target,'rohr2kugel');
		my kugel = null;
		my kugel2rohr = null;
		my kugel_connected = null;
		my kugel2rohr_docks = null;
		for (my kugeldock : kugeldocks) {
			kugel = DockGetConnectedPart(kugeldock);
			kugel2rohr_docks = ConnectedDocksOfType(kugel,'kugel2rohr');
			for (my dock : kugel2rohr_docks) {
				kugel_connected = DockGetConnectedPart(dock);
				if (IsSubTypeOf(kugel_connected,'kugel_stift')) {
					kugel_stift = true;
				}
			}
		}
		return kugel_stift;
	}

def snapHallerEtoKugelStiftManuell(target) {
    my kugel_stift = false;
    my stiftconnections = List();
    my hallerEconnections = List();
    my list = List();
    my kugeldocks = ConnectedDocksOfType(target,'rohr2kugel');
    my kugel = null;
    my kugel2rohr = null;
    my kugel_connected = null;
    my kugel2rohr_docks = null;
    if (Feature(target,'f_rohrtyp') eq 'rohr-normal') {
      for (my kugeldock : kugeldocks) {
        kugel = DockGetConnectedPart(kugeldock);
        kugel2rohr_docks = ConnectedDocksOfType(kugel,'kugel2rohr');
        for (my dock : kugel2rohr_docks) {
          kugel_connected = DockGetConnectedPart(dock);
          if (IsSubTypeOf(kugel_connected,'kugel_stift')) {
            stiftconnections = ListAdd(stiftconnections, kugel_connected);
          }
          if (Feature(kugel_connected,'f_rohrtyp') eq 'rohr-leitend' or Feature(kugel_connected,'f_rohrtyp') eq 'rohr-verbraucher') {
            hallerEconnections = ListAdd(hallerEconnections, kugel_connected);
          }
        }     
        if (Size(stiftconnections) gt 0 and Size(hallerEconnections) gt 0) {
          kugel_stift = true;
        }
      /* zuruecksetzen für naechste Kugel */
      stiftconnections = List();
      hallerEconnections = List();
      }
    }
    return kugel_stift;
  }

def schlitzFraesrohrKugelE() {
    my conflicts = List();
    my kugeln = List();
    my docks = List();
    my rohr = null;
    kugeln = GetComponentListOfType('kugel_std');
    kugeln = FilterList(kugeln,'element',`not Feature(element,'f_kugelLeitend');`);
    for (my kugel : kugeln) {      
      docks = ConnectedDocksOfType(kugel,'kugel2rohr');
      for (my dock : docks) {
        rohr = DockGetConnectedPart(dock);
        if (rohr) {
          if (IsSubTypeOf(rohr,'nktrohr') and Bool(Feature(rohr,'Schlitz')) AND  not IsSubTypeOf(rohr, 'ct_fake_fraesrohr')) {
            conflicts = ListAdd(conflicts,rohr);
          }
        }
      }
    }
    return conflicts;
  }

