def checkEinschubtuereHasGlasTop() {
	my klap = ChildrenListOfTypeDeep(Forest('mainstructure'), 'einschubtuerset');
	my normvol_list = List();
	my glass_list_bottom = List();

	if (Size(klap) gt 0 ){
		for (my k : klap) {
			my volcontent = Parent('mainstructure', k);
			if (volcontent){
				my normal_volumcont = Parent('mainstructure',volcontent);
				ListAdd(normvol_list, normal_volumcont);
			}
		};
		for (my v : normvol_list) {
			my related_to_volume = GetVolumeRefParts(v);
			my glass_list = FilterList(related_to_volume,'element',`not IsSubTypeOf(element,'normalglas');`);
			my glass_bottom = FilterList(glass_list,'element',`Round(PartRot(element)['z']) ne '-180' and Round(PartRot(element)['x']) ne '-180' ;`)[0];
			my glass_top = FilterList(glass_list,'element',`Round(PartRot(element)['z']) eq '-180' and Round(PartRot(element)['x']) eq '-180' ;`)[0];
			my distancetotop = Number(PartPos(glass_top)['z'] - PartPos(v)['z']);
			my distancetobottom = Number(PartPos(v)['z'] - PartPos(glass_bottom)['z']);
			if ( glass_top ne null and distancetotop lt '20' and distancetotop gt '0'){
				glass_list_bottom = ListAdd(glass_list_bottom,glass_top);
				}
			if ( glass_bottom ne null and distancetobottom lt '20' and distancetobottom gt '0'  ){
				glass_list_bottom = ListAdd(glass_list_bottom,glass_bottom);
				}
		};
	};
	return glass_list_bottom ;
}

def checkEinschubtuereWithTrafoE(){
my doors = ChildrenListOfTypeDeep(Forest('mainstructure'), 'einschubtuerset');
my conflict = List();

if (Size(doors) gt 0){
	for (my d : doors){
		my door_vol = ParentOfType(d, 'mainstructure','normal_volume');
		if (door_vol) {
			my vol_pos = PartPos(door_vol);
			my related_to_volume = GetVolumeRefParts(door_vol);
			my special_roh = List();
			for(my c : related_to_volume){
				if (Feature(c,'f_rohrtyp') eq 'rohr-verbraucher' and 
					Feature(c,'f_direction') eq 'Horizontal'){
					special_roh = ListAdd(special_roh, c);
				};
			};
			for (my rohr : special_roh){
				my rohr_pos = PartPos(rohr);
				if (Round(rohr_pos['z']) gt Round(vol_pos['z']) and Round(rohr_pos['x']) eq Round(vol_pos['x']) and Round(rohr_pos['y']) lt Round(vol_pos['y']) 
					and Feature(rohr,'f_verbraucherL') ne 'dummy_verbraucher' and Feature(rohr,'f_verbraucherM') ne 'dummy_verbraucher' and Feature(rohr,'f_verbraucherR') ne 'dummy_verbraucher')
					{
						ListAdd(conflict, rohr);
					};
				};
			}
		}
	}
	conflict;
};

def checkLightTypeWithDoor(){

my tuere = ChildrenListOfTypeDeep(Forest('mainstructure'), 'tuerelementset');
my klap = ChildrenListOfTypeDeep(Forest('mainstructure'), 'klapptuerset');

my nv_list = List();
my result = List();

if(Size(tuere) gt 0 ){
	for (my t : tuere){
		my volume =  ParentOfType(t, 'mainstructure', 'normal_volume');
		if (volume){
			ListAdd(nv_list, volume);
		} 
	}
};
if(Size(klap) gt 0 ){
	for (my k : klap){
		my volume =  ParentOfType(k, 'mainstructure', 'normal_volume');
		if (volume){
			ListAdd(nv_list, volume);
		} 
	}
};

for (my v : nv_list) {
	my related_to_volume = GetVolumeRefParts(v);
	my rohr_list = FilterList(related_to_volume,'element',`not IsSubTypeOf(element,'rohr');`);
	my vol_pos = PartPos(v);
	my rohr_leds = FilterList(rohr_list,'element',`not (Feature(element,'f_verbraucherL') eq 'led-warmweiss' 
	or Feature(element,'f_verbraucherM') eq 'led-warmweiss' 
	or Feature(element,'f_verbraucherR') eq 'led-warmweiss' 
	or Feature(element,'f_verbraucherL') eq 'led-kaltweiss' 
	or Feature(element,'f_verbraucherM') eq 'led-kaltweiss' 
	or Feature(element,'f_verbraucherR') eq 'led-kaltweiss');`);
	my rohr_leds = FilterList(rohr_leds,'element',`not (Feature(element,'f_direction') eq 'Horizontal');`);

	for (my rohr : rohr_leds){
		my rohr_pos = PartPos(rohr);
		if (Round(rohr_pos['z']) gt Round(vol_pos['z']) and Round(rohr_pos['x']) eq Round(vol_pos['x']) and Round(rohr_pos['y']) lt Round(vol_pos['y'])){
			ListAdd(result, rohr);
		}
	;}
};
result;
};

def checkUSBhallerE(list) {
    my usb_rohre = List();
    my featurelist = List('f_verbraucherL','f_verbraucherM','f_verbraucherR');
    for (my rohr : list) {
      for (my feature : featurelist) {
        if (HasFeature(rohr, feature)) {
          if (Feature(rohr,feature) eq 'usb-charger') {
          	usb_rohre = ListAdd(usb_rohre,rohr);
          }
        }
      }
    } 
   	return usb_rohre;
   }

def wrongUSBhallerE() {
    my conflicts = List();
    my rohre = GetComponentListOfType('normalrohr');
    my verbraucherrohre = FilterList(rohre,'element',`Feature(element,'f_rohrtyp') ne 'rohr-verbraucher';`);
    my checklist = FilterList(verbraucherrohre,'element',`not call horizontalPart(element);`);
    checklist = FilterList(checklist,'element',`call validUSBhallerE(element);`); /* here is door check but not a length check */
    conflicts = call checkUSBhallerE(checklist);
   	return conflicts;
   }
